function debounce(fn,wait){let timeoutId=null;return function(...args){if(timeoutId)clearTimeout(timeoutId);const context=this;timeoutId=setTimeout(()=>fn.apply(context,args),wait)}}function Logger(prefix,opts={}){const baseStyle="font-weight: bold; padding:2px 6px; border-radius: 4px;";const formattedPrefix=`[${prefix}]`;const styles={log:"background: #4caf50; color: white;"+baseStyle,error:"background: #f44336; color: white;"+baseStyle,warn:"background: #ff9800; color: black;"+baseStyle,debug:"background: #2196f3; color: white;"+baseStyle};const icons={log:"✅",error:"❌",warn:"⚠️",debug:"🔍"};function format(type,message,...rest){console[type](`%c${icons[type]} ${formattedPrefix}%c ${message}`,styles[type],"",...rest)}function log(message,...rest){format("log",message,...rest)}log.error=function(message,...rest){format("error",message,...rest)};log.warn=function(message,...rest){format("warn",message,...rest)};log.debug=function(message,...rest){if(opts.debug){format("debug",message,...rest)}};log.debugEnabled=!!opts.debug;return log}function qs(sel,root=document){return root.querySelector(sel)}function qsa(sel,root=document){return[...root.querySelectorAll(sel)]}function isVisible(el){if(!el)return false;const style=getComputedStyle(el);return el.offsetParent!==null&&style.visibility!=="hidden"&&style.display!=="none"&&style.opacity!=="0"}function findTargetInput(container=null){let target=qs("#query");if(target&&isVisible(target))return target;if(container){target=container.querySelector("input, textarea");if(target&&isVisible(target))return target}const candidates=qsa("input, textarea");target=candidates.find(isVisible)||null;return target}function getNativeValueSetter(el){const proto=el instanceof HTMLInputElement?HTMLInputElement.prototype:HTMLTextAreaElement.prototype;const desc=Object.getOwnPropertyDescriptor(proto,"value");return desc&&desc.set}function setInputValueReactive(el,value){const nativeSetter=getNativeValueSetter(el);if(nativeSetter){nativeSetter.call(el,value)}else{el.value=value}try{el.focus();if(typeof el.setSelectionRange==="function")el.setSelectionRange(value.length,value.length)}catch(err){}el.dispatchEvent(new Event("input",{bubbles:true}));el.dispatchEvent(new Event("change",{bubbles:true}));try{if(el._valueTracker?.setValue){el._valueTracker.setValue(value)}}catch(err){}}function ready(fn){if(document.readyState!=="loading"){fn()}else{document.addEventListener("DOMContentLoaded",fn)}}function isCacheValid(cacheEntry,durationMs){return cacheEntry&&cacheEntry.timestamp&&Date.now()-cacheEntry.timestamp<durationMs}function createMutationObserver(callback,options={},target=document.body){const defaultOptions={childList:true,subtree:true,...options};const observer=new MutationObserver(callback);observer.observe(target,defaultOptions);return observer}function createTemporaryObserver(conditionFn,callback,options={},target=document.body){const wrappedCallback=(mutations,observer)=>{if(conditionFn(mutations,observer)){observer.disconnect();return}callback(mutations,observer)};return createMutationObserver(wrappedCallback,options,target)}function waitForElement(selector,root=document,timeout=1e4){return new Promise((resolve,reject)=>{const element=root.querySelector(selector);if(element){resolve(element);return}const timeoutId=setTimeout(()=>{observer.disconnect();reject(new Error(`Element "${selector}" not found within ${timeout}ms`))},timeout);const observer=createTemporaryObserver(()=>{const found=root.querySelector(selector);if(found){clearTimeout(timeoutId);resolve(found);return true}return false},()=>{})})}function createButton(text,className="",clickHandler=null){const button=document.createElement("button");button.textContent=text;if(className)button.className=className;if(clickHandler)button.addEventListener("click",clickHandler);return button}function injectStyles(css,id=null){const style=document.createElement("style");style.textContent=css;if(id){const existing=document.getElementById(id);if(existing)existing.remove();style.id=id}document.head.appendChild(style);return style}function parseDate(dateString){if(!dateString)return NaN;const cleanedText=dateString.replace(/\s+/g," ").trim();const parsedTimestamp=Date.parse(cleanedText);return isNaN(parsedTimestamp)?new Date(cleanedText).getTime()||NaN:parsedTimestamp}if(typeof module!=="undefined"&&module.exports){module.exports={debounce:debounce,Logger:Logger,qs:qs,qsa:qsa,isVisible:isVisible,findTargetInput:findTargetInput,getNativeValueSetter:getNativeValueSetter,setInputValueReactive:setInputValueReactive,ready:ready,isCacheValid:isCacheValid,createMutationObserver:createMutationObserver,createButton:createButton,injectStyles:injectStyles,parseDate:parseDate,createTemporaryObserver:createTemporaryObserver,waitForElement:waitForElement}}if(typeof window!=="undefined"){window.debounce=debounce;window.Logger=Logger;window.qs=qs;window.qsa=qsa;window.isVisible=isVisible;window.findTargetInput=findTargetInput;window.getNativeValueSetter=getNativeValueSetter;window.setInputValueReactive=setInputValueReactive;window.ready=ready;window.isCacheValid=isCacheValid;window.createMutationObserver=createMutationObserver;window.createButton=createButton;window.injectStyles=injectStyles;window.parseDate=parseDate;window.createTemporaryObserver=createTemporaryObserver;window.waitForElement=waitForElement}
